#include<bits/stdc++.h>
using namespace std;

int main()
{
    int n,k;
    scanf("%d%d",&n,&k);
    int l=1,r=0;
    long long ans=1ll*n*k;
    while(l<=n)
    {
        int t=k/l;
        if(t==0)
        {
            r=n;
        }
        else
        {
            r=min(k/t,n);
        }
        ans-=1ll*(r-l+1)*t*(l+r)/2;
        l=r+1;
    }
    printf("%lld",ans);
    return 0;
}
